INSERT INTO tickets (event_id, type, description, price, link, perks, sort_order) VALUES ((SELECT id FROM events WHERE name = 'Foundations of Web Development Certification Course'), 'Certification Access Ticket', '🏅 Certification Ticket, program sürecine resmi, ölçümlenebilir ve mentör destekli olarak dahil olmanızı sağlar. Süreci bitirmeniz sonucu sertifika almaya hak kazanacaksınız.', 500, 'https://togather.lodos.io/events/foundations-frontend-web-development-certification-course-99241793086215583681/tickets', '["🍀 Gerçek proje ödevleri üzerinde çalışır, çıktılarınız için detaylı ve nitelikli geri bildirim alırsınız.","🧠 Süreç boyunca teknik destek ve mentörlük erişimine sahip olursunuz.","🎓 Program kriterlerini başarıyla tamamlamanız halinde sertifika almaya ve seçili programlarımız için burs olanaklarına hak kazanırsınız.","Certification Ticket, yalnızca bir katılım bileti değil; değerlendirilen, desteklenen ve belgelendirilen bir öğrenme deneyimidir."]', 1);
